// LEAKY VERSION: listeners accumulate in a Map
class EventBusLeaky {
  // This Map retains references to all callbacks forever
  private listeners: Map<string, Function[]> = new Map();
  on(event: string, cb: Function): void {
    if (!this.listeners.has(event)) {
      this.listeners.set(event, []);
    }
    this.listeners.get(event)!.push(cb);
  }
  // Never removing — memory grows unboundedly
}
// FIXED VERSION: add an off method to remove listeners
class EventBusFixed {
  private listeners: Map<string, Function[]> = new Map();
  on(event: string, cb: Function): void {
    if (!this.listeners.has(event)) {
      this.listeners.set(event, []);
    }
    this.listeners.get(event)!.push(cb);
    // Return an unsubscribe function for convenience
    return () => this.off(event, cb);
  }
  off(event: string, cb: Function): void {
    const cbs = this.listeners.get(event);
    if (cbs) {
      this.listeners.set(event, cbs.filter(fn => fn !== cb));
    }
  }
}
// Always unsubscribe when the listener is no longer needed
